// Normalize input to array of URLs and validate
const input = $input.first().json;
const body = input.body || input;

let urls = [];

if (body.urls && Array.isArray(body.urls)) {
  urls = body.urls;
} else if (body.url) {
  urls = [body.url];
} else {
  throw new Error('Missing required field: url or urls');
}

// Validate and normalize URLs (regex-based, URL constructor not available in sandbox)
const urlPattern = /^https?:\/\/[^\s/$.?#].[^\s]*$/i;
const validUrls = [];
const invalidUrls = [];

for (const rawUrl of urls) {
  const u = (rawUrl || '').trim();
  if (!u) continue;
  if (urlPattern.test(u)) {
    validUrls.push(u);
  } else {
    invalidUrls.push({ url: u, error: 'Invalid URL format' });
  }
}

if (validUrls.length === 0) {
  throw new Error('No valid URLs provided');
}

// Return each URL as a separate item for SplitInBatches
const items = validUrls.map(url => ({ json: { url, totalCount: validUrls.length, invalidUrls } }));
return items;

// Aggregate all results from the batch processing
const allItems = $('Call Article Ingest').all();
const normalizeData = $('Normalize URLs').first().json;

let success = 0;
let duplicate = 0;
let failed = 0;
const details = [];

for (const item of allItems) {
  const result = item.json;
  const status = result.status || 'unknown';

  if (status === 'ingested' || result.success === true) {
    success++;
    details.push({ url: result.url || '', status: 'success', title: result.title || '' });
  } else if (status === 'duplicate') {
    duplicate++;
    details.push({ url: result.url || '', status: 'duplicate' });
  } else {
    failed++;
    details.push({ url: result.url || '', status: 'failed', error: result.message || result.error || 'Unknown error' });
  }
}

// Include invalid URLs from initial validation
const invalidUrls = normalizeData.invalidUrls || [];
for (const inv of invalidUrls) {
  failed++;
  details.push({ url: inv.url, status: 'failed', error: inv.error });
}

return [{
  json: {
    total: success + duplicate + failed,
    success,
    duplicate,
    failed,
    details
  }
}];
